// Obtén los datos del WhatsApp Trigger
let wa_id = $('WhatsApp Trigger').first().json.contacts[0].wa_id

// Corrige el formato del número
let correctedNumber = wa_id.startsWith("521") ? "52" + wa_id.slice(3) : wa_id;

// Devuelve el número corregido como output del nodo
return {
  json: {
    recipient: correctedNumber,
    message: $('AI Agent').first().json.output
  }
};
